/// Wire format types for the polyglot WASM boundary.
///
/// The WASM boundary cannot link to tree-sitter C grammars (no stdio.h in
/// wasm32-unknown-unknown). The correct split is:
///
///   JS side  →  web-tree-sitter parses source  →  serializes PolyglotFnInput JSON
///   WASM side →  deserializes PolyglotFnInput   →  compiles to .gg topology
///
/// This file defines the JSON contract crossing that boundary.
use serde::{Deserialize, Serialize};

/// A single call argument — JS passes these as tagged variants.
#[derive(Serialize, Deserialize, Debug, Clone)]
#[serde(tag = "kind", rename_all = "lowercase")]
pub enum PolyglotArgInput {
    /// A simple named identifier (local variable or parameter).
    Identifier { name: String, #[serde(default)] ghost_mass: Option<serde_json::Value> },
    /// A string / number / bool / null literal.
    Literal { value: serde_json::Value, #[serde(default)] ghost_mass: Option<serde_json::Value> },
    /// A member access: `target.property`.
    Member { target: Box<PolyglotArgInput>, property: String, #[serde(default)] ghost_mass: Option<serde_json::Value> },
    /// A nested call — will be hoisted to a temp binding by the compiler.
    Call { callee: Box<PolyglotArgInput>, args: Vec<PolyglotArgInput>, #[serde(default)] ghost_mass: Option<serde_json::Value> },
}

/// A statement inside a polyglot function body.
#[derive(Serialize, Deserialize, Debug, Clone)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum PolyglotStmtInput {
    /// `let x = <expr>` / `val x = <expr>` / `x := <expr>`
    VarDecl {
        /// All bindings (destructure produces multiple).
        bindings: Vec<String>,
        /// Initializer — None means declaration without init (e.g. `let x;`).
        init: Option<PolyglotArgInput>,
        #[serde(default)] ghost_mass: Option<serde_json::Value>,
    },
    /// A bare call expression used for side effects.
    Call {
        callee: PolyglotArgInput,
        args: Vec<PolyglotArgInput>,
        #[serde(default)] ghost_mass: Option<serde_json::Value>,
    },
    /// `return <expr>` or `return` (None = void return).
    Return { value: Option<PolyglotArgInput>, #[serde(default)] ghost_mass: Option<serde_json::Value> },
    /// Parallel fan-out (`Promise.all`, `asyncio.gather`, `tokio::join!`, etc.)
    Parallel {
        bindings: Vec<String>,
        branches: Vec<PolyglotCallInput>,
        #[serde(default)] ghost_mass: Option<serde_json::Value>,
    },
}

/// A discrete call node for use inside `Parallel` branches.
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct PolyglotCallInput {
    pub callee: PolyglotArgInput,
    pub args: Vec<PolyglotArgInput>,
    pub assign_to: Option<String>,
    #[serde(default)]
    pub ghost_mass: Option<serde_json::Value>,
}

/// A single discrete testing assertion mapped either via exact User Tests or Automagically
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct PolyglotTestBinding {
    pub assertion_type: String,
    pub expected_value: serde_json::Value,
    #[serde(default)]
    pub ghost_mass: Option<serde_json::Value>,
}

/// The top-level input to `compile_polyglot_fn` — one function's worth of data
/// extracted by web-tree-sitter on the JS side and shipped across the WASM boundary.
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct PolyglotFnInput {
    /// Function name (used as topology prefix).
    pub name: String,
    /// Parameter names (single input param, destructured names, etc.)
    pub params: Vec<String>,
    /// Ordered body statements.
    pub body: Vec<PolyglotStmtInput>,
    /// Source language tag (informational — does not change compilation logic).
    pub language: Option<String>,
    /// File path (used in topology metadata and node IDs).
    pub file_path: Option<String>,
    /// Mathematically verified execution bounds defining strictly what output correctness is.
    pub test_bindings: Option<Vec<PolyglotTestBinding>>,
}
